arguments.command:
mkdir -p /tmp/nint_test && cd /tmp/nint_test && dotnet new console --force -n NintTest -o . --no-restore 2>&1 | tail -3 && cat <<'EOF' > Program.cs
using System;

unsafe
{
    Span<nint> span = stackalloc nint[4];
    span[0] = 10;
    span[1] = 20;
    span[2] = 30;
    span[3] = 40;

    Console.WriteLine($"Length: {span.Length}");
    for (int i = 0; i < span.Length; i++)
        Console.WriteLine($"span[{i}] = {span[i]}");

    Console.WriteLine($"Element size: {sizeof(nint)} bytes");
}
EOF
# Enable unsafe and set lang version
sed -i 's|</PropertyGroup>|<AllowUnsafeBlocks>true</AllowUnsafeBlocks><LangVersion>latest</LangVersion></PropertyGroup>|' NintTest.csproj && dotnet run 2>&1

